import{_ as a,o as s,c as i,a2 as t}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Compte & Audiences","description":"","frontmatter":{"title":"Compte & Audiences"},"headers":[],"relativePath":"docs/fr/faq/account-audiences.md","filePath":"docs/fr/faq/account-audiences.md"}'),r={name:"docs/fr/faq/account-audiences.md"};function o(n,e,u,l,c,d){return s(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="compte-equipe-audiences" tabindex="-1">Compte, Équipe &amp; Audiences <a class="header-anchor" href="#compte-equipe-audiences" aria-label="Permalink to &quot;Compte, Équipe &amp; Audiences&quot;">​</a></h1><h2 id="comment-ajouter-un-nouvel-utilisateur" tabindex="-1">Comment ajouter un nouvel utilisateur ? <a class="header-anchor" href="#comment-ajouter-un-nouvel-utilisateur" aria-label="Permalink to &quot;Comment ajouter un nouvel utilisateur ?&quot;">​</a></h2><p>Rendez-vous dans <strong>Mon Organisation → Équipe</strong> et cliquez sur <code>+ Ajouter un membre</code>. Recommandé : ayez toujours au moins un backup pour assurer la réactivité sous 48h.</p><h2 id="comment-referencer-une-nouvelle-audience" tabindex="-1">Comment référencer une nouvelle audience ? <a class="header-anchor" href="#comment-referencer-une-nouvelle-audience" aria-label="Permalink to &quot;Comment référencer une nouvelle audience ?&quot;">​</a></h2><p>Allez dans <strong>Monétisation → Catalogue</strong> et cliquez sur <code>+ Nouvelle audience</code>. Remplissez les fiches avec soin (Marque, Persona, Panier Moyen) — c&#39;est ce qui convaincra les annonceurs.</p><p>→ <a href="/handbook/docs/fr/publishers/audience-setup.html">Guide détaillé : Configuration d&#39;Audience</a></p><h2 id="faut-il-creer-plusieurs-comptes-si-j-ai-plusieurs-sites" tabindex="-1">Faut-il créer plusieurs comptes si j&#39;ai plusieurs sites ? <a class="header-anchor" href="#faut-il-creer-plusieurs-comptes-si-j-ai-plusieurs-sites" aria-label="Permalink to &quot;Faut-il créer plusieurs comptes si j&#39;ai plusieurs sites ?&quot;">​</a></h2><p>Non. Vous pouvez gérer autant d&#39;audiences que vous le souhaitez depuis un seul compte getinside. Chaque site peut avoir sa propre fiche audience indépendante.</p><h2 id="getinside-est-il-present-a-l-international" tabindex="-1">getinside est-il présent à l&#39;international ? <a class="header-anchor" href="#getinside-est-il-present-a-l-international" aria-label="Permalink to &quot;getinside est-il présent à l&#39;international ?&quot;">​</a></h2><p>Oui, getinside opère dans toute l&#39;Europe. Vous pouvez ajouter vos audiences européennes et recevoir des campagnes ciblées pour ces pays.</p><h2 id="comment-suivre-mes-filleuls-affiliation" tabindex="-1">Comment suivre mes filleuls (affiliation) ? <a class="header-anchor" href="#comment-suivre-mes-filleuls-affiliation" aria-label="Permalink to &quot;Comment suivre mes filleuls (affiliation) ?&quot;">​</a></h2><p>L&#39;état de vos filleuls est visible dans l&#39;onglet <strong>Affiliation</strong>. Vous touchez une commission récurrente de <strong>20%</strong> sur les frais de plateforme générés par leur activité. Vos gains apparaissent dans <strong>Transactions → Revenus</strong> et peuvent être retirés ou réinvestis depuis votre Wallet.</p><h2 id="pourquoi-mon-score-distributeur-a-baisse" tabindex="-1">Pourquoi mon &quot;Score Distributeur&quot; a baissé ? <a class="header-anchor" href="#pourquoi-mon-score-distributeur-a-baisse" aria-label="Permalink to &quot;Pourquoi mon &quot;Score Distributeur&quot; a baissé ?&quot;">​</a></h2><p>Le score est recalculé dynamiquement. Causes fréquentes : délai de réponse &gt; 48h, refus de campagnes sans contre-proposition, volumes distribués inférieurs aux engagements, CPM trop élevé vs la concurrence.</p><p>→ <a href="/handbook/docs/fr/publishers/score-distributor.html">Guide complet : Score Distributeur</a></p>',15)])])}const f=a(r,[["render",o]]);export{m as __pageData,f as default};
